import json

def extract_and_validate(clean_text, schema_class):
    response = claude.messages.create(
        model="claude-opus-4-5",
        max_tokens=1024,
        messages=[{
            "role": "user",
            "content": f"Extract data per schema from:\n{clean_text}"
        }]
    )
    raw = json.loads(response.content[0].text)
    validated = schema_class(**raw)  # Pydantic validates and coerces
    return validated

